#include <iostream>
#include <memory>
#include <string>

// Интерфейс Text
class Text {
public:
    virtual ~Text() = default;
    virtual std::string write() const = 0;
};

// Базовый класс PlainText
class PlainText : public Text {
private:
    std::string content;

public:
    explicit PlainText(const std::string& text) : content(text) {}

    std::string write() const override {
        return content;
    }
};

// Абстрактный декоратор TextDecorator
class TextDecorator : public Text {
protected:
    std::shared_ptr<Text> text;

public:
    explicit TextDecorator(std::shared_ptr<Text> txt) : text(std::move(txt)) {}

    std::string write() const override {
        return text->write();
    }
};

// Декоратор Bold
class Bold : public TextDecorator {
public:
    explicit Bold(std::shared_ptr<Text> txt) : TextDecorator(std::move(txt)) {}

    std::string write() const override {
        return "\033[1m" + TextDecorator::write() + "\033[0m";
    }
};

// Декоратор Italic
class Italic : public TextDecorator {
public:
    explicit Italic(std::shared_ptr<Text> txt) : TextDecorator(std::move(txt)) {}

    std::string write() const override {
        return "\033[3m" + TextDecorator::write() + "\033[0m";
    }
};

// Декоратор Underline
class Underline : public TextDecorator {
public:
    explicit Underline(std::shared_ptr<Text> txt) : TextDecorator(std::move(txt)) {}

    std::string write() const override {
        return "\033[4m" + TextDecorator::write() + "\033[0m";
    }
};

int main() {
    // Базовый текст
    auto plain = std::make_shared<PlainText>("Hello, Decorator Pattern!");

    // Применяем один стиль
    auto bold = std::make_shared<Bold>(plain);
    std::cout << bold->write() << std::endl;

    // Применяем несколько стилей
    auto boldItalic = std::make_shared<Italic>(std::make_shared<Bold>(plain));
    std::cout << boldItalic->write() << std::endl;

    // Все три стиля
    auto fullStyle = std::make_shared<Underline>(
        std::make_shared<Italic>(
            std::make_shared<Bold>(plain)
        )
    );
    std::cout << fullStyle->write() << std::endl;

    // Другой текст с комбинацией стилей
    auto anotherText = std::make_shared<PlainText>("Styled Text Example");
    auto styled = std::make_shared<Bold>(
        std::make_shared<Underline>(anotherText)
    );
    std::cout << styled->write() << std::endl;

    return 0;
}

